/**
 * Generate Loops firewall config.
 *
 * Data source: https://loops.so/docs/api-reference/intro
 *
 * Loops is an email marketing platform for SaaS.
 * Uses Bearer token authentication.
 * Token format: 32-char hex string.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://loops.so/docs/api-reference/intro";
// Token format: 32-char hex string
// e.g. d2d561f5ff80136f69b4b5a31b9fb3c9
const PLACEHOLDER_VALUE = "c0ffee5afe10ca1c0ffee5afe10ca1c0";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Loops API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:loops",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const loopsFirewall = {",
    '  name: "loops",',
    '  description: "Loops API",',
    "  placeholders: {",
    `    LOOPS_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://app.loops.so/api",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.LOOPS_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Loops firewall config...");
  const ts = generateTypeScript();
  writeOutput("loops", ts, import.meta.dirname);
}
